// Ghiath reminder scheduler. Runs every minute. Scans /data/vault/reminders for
// reminder notes, fires an ntfy alarm when one comes due, keeps re-nagging until
// the user acknowledges (or the ack window elapses), and sends one Telegram ping
// on the first fire. The agent's "reminders" skill only writes the notes; this
// workflow is the engine that delivers them.
//
// Reminder note front-matter (see skills/reminders/SKILL.md):
//   type: reminder | status: scheduled->firing->acknowledged|missed
//   channel: ntfy | when: ISO8601 w/ offset | title | message
//   priority: 1-5 | ackWindowMin: N | id: rmd-...
const fs = require('fs');
const path = require('path');

const DIR = '/data/vault/reminders';
const now = Date.now();

const NTFY_URL = ($env.NTFY_URL || 'http://ntfy:80').replace(/\/+$/, '');
const NTFY_TOPIC = $env.NTFY_TOPIC || 'ghiath-alarm';
const NTFY_TOKEN = $env.NTFY_TOKEN || '';
const TG_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';
const TG_CHAT = $env.TELEGRAM_CHAT_ID || '';
const WEBHOOK = ($env.WEBHOOK_URL || $env.N8N_WEBHOOK_URL || '').replace(/\/+$/, '');

let files = [];
try {
  files = fs.readdirSync(DIR).filter((f) => f.endsWith('.md'));
} catch (e) {
  return [{ json: { note: 'no reminders folder yet', dir: DIR } }];
}

const parseFm = (raw) => {
  const m = raw.match(/^---\n([\s\S]*?)\n---/);
  if (!m) return null;
  const fm = {};
  for (const line of m[1].split('\n')) {
    const mm = line.match(/^([A-Za-z0-9_]+):\s*(.*)$/);
    if (mm) fm[mm[1]] = mm[2].trim();
  }
  return { fm, block: m[1], full: m[0], body: raw.slice(m[0].length).replace(/^\n+/, '') };
};

const setField = (block, key, val) => {
  const re = new RegExp('^' + key + ':.*$', 'm');
  if (re.test(block)) return block.replace(re, key + ': ' + val);
  return block + '\n' + key + ': ' + val;
};

const out = [];

for (const file of files) {
  const fp = path.join(DIR, file);
  let raw;
  try { raw = fs.readFileSync(fp, 'utf8'); } catch (e) { continue; }
  const parsed = parseFm(raw);
  if (!parsed) continue;
  const fm = parsed.fm;
  if ((fm.type || '') !== 'reminder') continue;

  // Calendar reminders fire natively through Google; nothing to do here.
  if ((fm.channel || 'ntfy').toLowerCase() === 'calendar') continue;

  const status = (fm.status || 'scheduled').toLowerCase();
  const whenMs = Date.parse(fm.when || '');
  if (isNaN(whenMs)) continue;

  const ackWindowMin = parseInt(fm.ackWindowMin || '15', 10);
  const priority = Math.max(1, Math.min(5, parseInt(fm.priority || '5', 10)));
  const title = fm.title || 'Reminder';
  const message = fm.message || parsed.body.split('\n')[0] || title;
  const id = fm.id || file.replace(/\.md$/, '');

  let doSend = false, firstFire = false, newStatus = null, firedAt = fm.firedAt || '';

  if (status === 'scheduled' && now >= whenMs) {
    doSend = true; firstFire = true; newStatus = 'firing';
    firedAt = new Date(now).toISOString();
  } else if (status === 'firing') {
    const firedMs = Date.parse(firedAt) || now;
    if (now <= firedMs + ackWindowMin * 60000) {
      doSend = true; // keep nagging
    } else {
      newStatus = 'missed';
    }
  } else {
    continue; // scheduled-but-future, acknowledged, missed, etc.
  }

  if (doSend && NTFY_URL) {
    const actions = WEBHOOK
      ? [{
          action: 'http',
          label: 'Acknowledge',
          url: WEBHOOK + '/webhook/reminder-ack?id=' + encodeURIComponent(id),
          method: 'POST',
          clear: true,
        }]
      : [];
    const headers = { 'Content-Type': 'application/json' };
    if (NTFY_TOKEN) headers.Authorization = 'Bearer ' + NTFY_TOKEN;
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: NTFY_URL,
        headers,
        body: { topic: NTFY_TOPIC, title, message, priority, tags: ['alarm_clock'], actions },
        json: true,
      });
    } catch (e) { /* transient; retry next minute */ }
  }

  if (doSend && firstFire && TG_TOKEN && TG_CHAT) {
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.telegram.org/bot' + TG_TOKEN + '/sendMessage',
        body: { chat_id: TG_CHAT, text: '⏰ ' + title + '\n' + message, disable_web_page_preview: true },
        json: true,
      });
    } catch (e) { /* ignore */ }
  }

  if (newStatus || firstFire) {
    let block = parsed.block;
    if (newStatus) block = setField(block, 'status', newStatus);
    if (firstFire) block = setField(block, 'firedAt', firedAt);
    const rebuilt = raw.replace(/^---\n[\s\S]*?\n---/, '---\n' + block + '\n---');
    try { fs.writeFileSync(fp, rebuilt); } catch (e) { /* ignore */ }
  }

  out.push({ json: { id, title, sent: doSend, firstFire, status: newStatus || status } });
}

return out.length ? out : [{ json: { checked: files.length, fired: 0 } }];
